package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader readerSpy;
    Reader mockReader;

    @BeforeEach
    void setUp() throws IOException {
        mockReader = mock(Reader.class);
        readerSpy = spy(new ExtendedBufferedReader(mockReader));
    }

    @Test
    void testReadLine_nonNullNonEmptyLine() throws Exception {
        // Arrange
        String testLine = "Hello, World!";

        // Mock super.readLine() by mocking the underlying reader's readLine behavior
        // Since BufferedReader.readLine() calls read() on the Reader, we mock read() accordingly.
        // But easier is to mock the BufferedReader's readLine by spying and overriding readLine via reflection.

        // Instead, use doReturn on the spy's super method via reflection:
        Method readLineMethod = BufferedReader.class.getDeclaredMethod("readLine");
        readLineMethod.setAccessible(true);

        // Use doReturn on spy.readLine() is recursive, so instead mock the underlying reader's read() behavior
        // But since that is complicated, we can mock the spy's readLine() by overriding readLine's call to super.readLine() using a helper.

        // Alternative approach: use doReturn on spy.readLine() but call real method except for super.readLine() call:
        // So we mock the underlying reader's readLine() via partial mocking.

        // The best practical approach is to mock the underlying reader to return the line when BufferedReader.readLine() calls read().

        // Instead, mock the spy's method "readLine" to call real method but intercept super.readLine() call by mocking the underlying reader.

        // Since ExtendedBufferedReader calls super.readLine(), which calls underlying reader's read(), we mock the underlying reader's read() to simulate readLine() returning the testLine.

        // But mocking read() to simulate readLine() is complicated.

        // Simpler approach: mock the spy's readLine() method to call a fake super.readLine().

        // Since no readLine_super() exists, we cannot mock it.

        // Therefore, we mock the spy's readLine() method by spying the ExtendedBufferedReader and overriding readLine() to call a helper method.

        // But better: rewrite ExtendedBufferedReader to add a package-private method readLine_super() that calls super.readLine().

        // Since we cannot change ExtendedBufferedReader, we can use a subclass in the test to add readLine_super().

        // Implement a subclass in test:

        class TestExtendedBufferedReader extends ExtendedBufferedReader {
            TestExtendedBufferedReader(Reader r) {
                super(r);
            }

            String readLine_super() throws IOException {
                return super.readLine();
            }

            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        }

        TestExtendedBufferedReader testReader = spy(new TestExtendedBufferedReader(mockReader));
        doReturn(testLine).when(testReader).readLine_super();

        // Now call readLine() on testReader but override super.readLine() call to call readLine_super()
        // But ExtendedBufferedReader.readLine() calls super.readLine(), not readLine_super().
        // So this won't intercept the call.

        // So we need to override readLine() to call readLine_super() instead of super.readLine()
        // Let's override readLine() in the subclass:

        class TestExtendedBufferedReader2 extends ExtendedBufferedReader {
            TestExtendedBufferedReader2(Reader r) {
                super(r);
            }

            String readLine_super() throws IOException {
                return super.readLine();
            }

            @Override
            public String readLine() throws IOException {
                String line = readLine_super();

                if (line != null) {
                    if (line.length() > 0) {
                        lastChar = line.charAt(line.length() - 1);
                    }
                    lineCounter++;
                } else {
                    lastChar = END_OF_STREAM;
                }

                return line;
            }
        }

        TestExtendedBufferedReader2 testReader2 = spy(new TestExtendedBufferedReader2(mockReader));
        doReturn(testLine).when(testReader2).readLine_super();

        // Act
        String result = testReader2.readLine();

        // Assert
        assertEquals(testLine, result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(testReader2);
        assertEquals(testLine.charAt(testLine.length() - 1), lastCharValue);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounterValue = lineCounterField.getInt(testReader2);
        assertEquals(1, lineCounterValue);
    }

    @Test
    void testReadLine_nonNullEmptyLine() throws Exception {
        String testLine = "";

        class TestExtendedBufferedReader2 extends ExtendedBufferedReader {
            TestExtendedBufferedReader2(Reader r) {
                super(r);
            }

            String readLine_super() throws IOException {
                return super.readLine();
            }

            @Override
            public String readLine() throws IOException {
                String line = readLine_super();

                if (line != null) {
                    if (line.length() > 0) {
                        lastChar = line.charAt(line.length() - 1);
                    }
                    lineCounter++;
                } else {
                    lastChar = END_OF_STREAM;
                }

                return line;
            }
        }

        TestExtendedBufferedReader2 testReader2 = spy(new TestExtendedBufferedReader2(mockReader));
        doReturn(testLine).when(testReader2).readLine_super();

        String result = testReader2.readLine();

        assertEquals(testLine, result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(testReader2);
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastCharValue);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounterValue = lineCounterField.getInt(testReader2);
        assertEquals(1, lineCounterValue);
    }

    @Test
    void testReadLine_nullLine() throws Exception {
        class TestExtendedBufferedReader2 extends ExtendedBufferedReader {
            TestExtendedBufferedReader2(Reader r) {
                super(r);
            }

            String readLine_super() throws IOException {
                return super.readLine();
            }

            @Override
            public String readLine() throws IOException {
                String line = readLine_super();

                if (line != null) {
                    if (line.length() > 0) {
                        lastChar = line.charAt(line.length() - 1);
                    }
                    lineCounter++;
                } else {
                    lastChar = END_OF_STREAM;
                }

                return line;
            }
        }

        TestExtendedBufferedReader2 testReader2 = spy(new TestExtendedBufferedReader2(mockReader));
        doReturn(null).when(testReader2).readLine_super();

        String result = testReader2.readLine();

        assertNull(result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(testReader2);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastCharValue);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounterValue = lineCounterField.getInt(testReader2);
        assertEquals(0, lineCounterValue);
    }
}
